import type { Metadata } from "next";
import BenefitScreening from "./BenefitScreening";

export const metadata: Metadata = {
    title: "給付金 / 生活支援給付 審査 | ぐんじょう 自治体業務",
    description:
        "自治体の審査担当が、給付金・生活支援給付の申請を多段階（申請受付 → 書類審査 → 資格判定 → 世帯・収入調査 → 決定 → 支給）で審査する画面。申請一覧から案件を選び、各段階を「次へ進める」「差戻し」「却下」で進行させる。必要書類チェックが書類審査をゲートし、収入・資産が基準額以内かを判定し、承認/却下の決定は署名・確定後にロックされる監査可能な記録として残る。支給額は世帯人数・収入から自動計算する。",
};

export default function BenefitScreeningPage() {
    return <BenefitScreening />;
}

"use client";

import * as React from "react";
import {
    IconArrowBackUp,
    IconArrowRight,
    IconBan,
    IconCircleCheck,
    IconClipboardList,
    IconCoin,
    IconHome,
    IconUsers,
} from "@tabler/icons-react";
import type { ColumnDef } from "@tanstack/react-table";

import {
    Alert,
    AlertDescription,
    AlertTitle,
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
    ApprovalSteps,
    Badge,
    Banner,
    Button,
    Card,
    CardContent,
    CardDescription,
    CardHeader,
    CardTitle,
    Checkbox,
    CoSign,
    type CoSignValue,
    DataTable,
    formatCurrency,
    MetadataList,
    ReferenceValue,
    Select,
    Separator,
    SignedRecord,
    type SignedRecordValue,
    Statistic,
    Tag,
    Textarea,
} from "@gunjo/ui";

import {
    type Application,
    APPLICATIONS,
    ASSET_THRESHOLD,
    BENEFIT_LABELS,
    BENEFIT_PAYMENT_KIND,
    canAdvance,
    computeBenefitAmount,
    evaluateEligibility,
    initialScreeningState,
    nextStage,
    priorStages,
    REQUIRED_DOCS,
    type ScreeningState,
    STAGE_LABELS,
    STAGE_ORDER,
    STAGE_REQUIREMENT,
    stageStateFor,
    type StageId,
} from "./data";

const ME = "審査担当 山田"; // ログイン中の審査担当
const ME_ID = "yamada";

function fmtDateTime(iso: string): string {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return iso;
    const p = (n: number) => String(n).padStart(2, "0");
    return `${d.getFullYear()}/${p(d.getMonth() + 1)}/${p(d.getDate())} ${p(
        d.getHours(),
    )}:${p(d.getMinutes())}`;
}

function fmtDate(iso: string): string {
    return iso.replaceAll("-", "/");
}

function daysUntil(iso: string): number {
    const due = new Date(iso + "T00:00:00");
    const today = new Date("2026-06-24T00:00:00");
    return Math.round((due.getTime() - today.getTime()) / 86_400_000);
}

// SLA フラグ：期限までの残日数で判定（色だけに依存しない：文言 + アイコン的記号）
function SlaFlag({ dueAt }: { dueAt: string }) {
    const d = daysUntil(dueAt);
    if (d < 0) {
        return (
            <Badge variant="destructive">期限超過 {Math.abs(d)}日</Badge>
        );
    }
    if (d <= 2) {
        return <Badge variant="warning">残り{d}日</Badge>;
    }
    return <Badge variant="outline">残り{d}日</Badge>;
}

const TYPE_ICON: Record<Application["type"], React.ReactNode> = {
    livelihood: <IconCoin className="h-4 w-4" aria-hidden />,
    childRearing: <IconUsers className="h-4 w-4" aria-hidden />,
    housing: <IconHome className="h-4 w-4" aria-hidden />,
};

export default function BenefitScreening() {
    // 申請ごとの審査状態をまとめて保持
    const [states, setStates] = React.useState<Record<string, ScreeningState>>(
        () =>
            Object.fromEntries(
                APPLICATIONS.map((a) => [a.id, initialScreeningState(a)]),
            ),
    );
    const [selectedId, setSelectedId] = React.useState<string>(
        APPLICATIONS[0].id,
    );
    // 決定セクションの署名状態（SignedRecord）
    const [decisions, setDecisions] = React.useState<
        Record<string, SignedRecordValue>
    >(() =>
        Object.fromEntries(
            APPLICATIONS.map((a) => [a.id, { status: "draft", addenda: [] }]),
        ),
    );
    // 2人確認（CoSign）の状態
    const [coSigns, setCoSigns] = React.useState<
        Record<string, CoSignValue | undefined>
    >({});
    // 決定本文（承認/却下 + 理由）
    const [decisionKind, setDecisionKind] = React.useState<
        Record<string, "approve" | "reject">
    >({});
    const [decisionReason, setDecisionReason] = React.useState<
        Record<string, string>
    >({});
    // 差戻し理由
    const [sendBackTarget, setSendBackTarget] = React.useState<StageId | "">("");
    const [sendBackReason, setSendBackReason] = React.useState("");
    const [rejectReason, setRejectReason] = React.useState("");
    // 差戻しメモ（戻された段階に差戻し理由を表示する用）
    const [sendBackNote, setSendBackNote] = React.useState<
        Record<
            string,
            { stage: StageId; reason: string; actor: string; at: string }
        >
    >({});

    const app = APPLICATIONS.find((a) => a.id === selectedId)!;
    const state = states[selectedId];
    const decision = decisions[selectedId];
    const coSign = coSigns[selectedId];
    const elig = evaluateEligibility(app, state);
    const amount = computeBenefitAmount(
        app.type,
        app.householdSize,
        app.monthlyIncome,
    );

    const patchState = (patch: Partial<ScreeningState>) =>
        setStates((prev) => ({
            ...prev,
            [selectedId]: { ...prev[selectedId], ...patch },
        }));

    // ---- 状態遷移アクション（ハンドロール状態機械）-------------------------
    const advance = () => {
        if (!canAdvance(app, state)) return;
        const next = nextStage(state.currentStage);
        if (!next) return;
        patchState({
            currentStage: next,
            completed: {
                ...state.completed,
                [state.currentStage]: {
                    actor: ME,
                    at: new Date().toISOString(),
                },
            },
        });
    };

    const sendBack = () => {
        if (!sendBackTarget || !sendBackReason.trim()) return;
        const target = sendBackTarget;
        // 戻し先より前の完了記録だけを残す
        const keep: ScreeningState["completed"] = {};
        for (const s of STAGE_ORDER) {
            if (s === target) break;
            if (state.completed[s]) keep[s] = state.completed[s];
        }
        const targetIdx = STAGE_ORDER.indexOf(target);
        patchState({
            currentStage: target,
            completed: keep,
            status: "inReview",
            // 差戻しに伴い、戻し先以降の確定フラグを巻き戻す
            eligibilityConfirmed:
                targetIdx > STAGE_ORDER.indexOf("eligibility")
                    ? state.eligibilityConfirmed
                    : false,
            householdSurveyDone:
                targetIdx > STAGE_ORDER.indexOf("household")
                    ? state.householdSurveyDone
                    : false,
        });
        setSendBackNote((prev) => ({
            ...prev,
            [selectedId]: {
                stage: target,
                reason: sendBackReason.trim(),
                actor: ME,
                at: new Date().toISOString(),
            },
        }));
        setSendBackTarget("");
        setSendBackReason("");
    };

    const reject = () => {
        if (!rejectReason.trim()) return;
        patchState({
            status: "rejected",
            completed: {
                ...state.completed,
                [state.currentStage]: {
                    actor: ME,
                    at: new Date().toISOString(),
                    note: rejectReason.trim(),
                },
            },
        });
        setRejectReason("");
    };

    // 決定の署名完了で「決定」→「支給」へ自動進行
    const onDecisionChange = (v: SignedRecordValue) => {
        setDecisions((prev) => ({ ...prev, [selectedId]: v }));
        if (v.status === "signed" && state.currentStage === "decision") {
            const kind = decisionKind[selectedId] ?? "approve";
            if (kind === "approve") {
                patchState({
                    currentStage: "payment",
                    status: "approved",
                    completed: {
                        ...state.completed,
                        decision: {
                            actor: v.signedBy ?? ME,
                            at: v.signedAt ?? new Date().toISOString(),
                            note: `承認：${decisionReason[selectedId] ?? ""}`,
                        },
                    },
                });
            } else {
                patchState({
                    status: "rejected",
                    completed: {
                        ...state.completed,
                        decision: {
                            actor: v.signedBy ?? ME,
                            at: v.signedAt ?? new Date().toISOString(),
                            note: `却下：${decisionReason[selectedId] ?? ""}`,
                        },
                    },
                });
            }
        }
    };

    const completePayment = () => {
        patchState({
            completed: {
                ...state.completed,
                payment: { actor: ME, at: new Date().toISOString() },
            },
        });
    };

    // ---- ApprovalSteps 用のステップ配列を派生 ------------------------------
    const approvalSteps = STAGE_ORDER.map((s) => {
        const rec = state.completed[s];
        const note = sendBackNote[selectedId];
        return {
            label: STAGE_LABELS[s],
            state: stageStateFor(s, state),
            actor: rec?.actor,
            timestamp: rec?.at ? fmtDateTime(rec.at) : undefined,
            comment:
                rec?.note ??
                (note && note.stage === s
                    ? `差戻し：${note.reason}（${note.actor} ${fmtDateTime(
                          note.at,
                      )}）`
                    : undefined),
        };
    });

    // ---- 申請一覧 (DataTable) ----------------------------------------------
    const columns = React.useMemo<ColumnDef<Application>[]>(
        () => [
            {
                accessorKey: "id",
                header: "申請番号",
                cell: ({ row }) => (
                    <span className="font-medium tabular-nums">
                        {row.original.id}
                    </span>
                ),
            },
            {
                accessorKey: "type",
                header: "給付種別",
                cell: ({ row }) => (
                    <span className="inline-flex items-center gap-1.5">
                        {TYPE_ICON[row.original.type]}
                        {BENEFIT_LABELS[row.original.type]}
                    </span>
                ),
            },
            {
                accessorKey: "applicantName",
                header: "申請者 / 世帯",
                cell: ({ row }) => (
                    <span>
                        {row.original.applicantName}
                        <span className="ml-1 text-xs text-muted-foreground">
                            （{row.original.householdSize}人世帯）
                        </span>
                    </span>
                ),
            },
            {
                accessorKey: "appliedAt",
                header: "申請日",
                cell: ({ row }) => (
                    <span className="tabular-nums">
                        {fmtDate(row.original.appliedAt)}
                    </span>
                ),
            },
            {
                id: "stage",
                header: "現在の審査段階",
                cell: ({ row }) => {
                    const st = states[row.original.id];
                    if (st.status === "approved") {
                        return <Badge variant="success">支給決定</Badge>;
                    }
                    if (st.status === "rejected") {
                        return <Badge variant="destructive">却下</Badge>;
                    }
                    return (
                        <Tag variant="outline">
                            {STAGE_LABELS[st.currentStage]}
                        </Tag>
                    );
                },
            },
            {
                id: "sla",
                header: "処理期限",
                cell: ({ row }) => <SlaFlag dueAt={row.original.dueAt} />,
            },
        ],
        [states],
    );

    const advanceable = canAdvance(app, state);
    const isTerminal = state.status !== "inReview";

    return (
        <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 lg:py-10">
            <header className="mb-6">
                <p className="text-xs font-medium text-muted-foreground">
                    群青市役所 ・ 福祉給付課
                </p>
                <h1 className="text-2xl font-bold tracking-tight sm:text-3xl">
                    給付金 / 生活支援給付 審査
                </h1>
                <p className="mt-1 text-sm text-muted-foreground">
                    申請を多段階で審査し、承認・却下を決定します。
                    ログイン中：{ME}
                </p>
            </header>

            {/* 申請一覧 */}
            <section aria-labelledby="queue-heading" className="mb-8">
                <h2
                    id="queue-heading"
                    className="mb-3 flex items-center gap-2 text-lg font-semibold"
                >
                    <IconClipboardList className="h-5 w-5" aria-hidden />
                    申請一覧
                </h2>
                <DataTable
                    columns={columns}
                    data={APPLICATIONS}
                    filter={{
                        columnId: "applicantName",
                        placeholder: "申請者名で絞り込み",
                    }}
                    onRowClick={(row) => setSelectedId(row.id)}
                    getRowState={(row) =>
                        row.id === selectedId ? "selected" : undefined
                    }
                    renderCard={(row) => (
                        <button
                            type="button"
                            onClick={() => setSelectedId(row.id)}
                            className="flex w-full flex-col gap-1 rounded-lg border border-border bg-card p-3 text-left"
                        >
                            <div className="flex items-center justify-between gap-2">
                                <span className="font-medium tabular-nums">
                                    {row.id}
                                </span>
                                <SlaFlag dueAt={row.dueAt} />
                            </div>
                            <span className="inline-flex items-center gap-1.5 text-sm">
                                {TYPE_ICON[row.type]}
                                {BENEFIT_LABELS[row.type]}
                            </span>
                            <span className="text-sm text-muted-foreground">
                                {row.applicantName}（{row.householdSize}人世帯）
                            </span>
                        </button>
                    )}
                />
            </section>

            {/* 選択中の申請の審査 */}
            <section aria-labelledby="case-heading">
                <div className="mb-3 flex flex-wrap items-center justify-between gap-2">
                    <h2
                        id="case-heading"
                        className="text-lg font-semibold"
                    >
                        審査：{app.applicantName} 様
                        <span className="ml-2 align-middle text-sm font-normal text-muted-foreground tabular-nums">
                            {app.id}
                        </span>
                    </h2>
                    <Badge
                        variant={
                            state.status === "approved"
                                ? "success"
                                : state.status === "rejected"
                                  ? "destructive"
                                  : "info"
                        }
                    >
                        {state.status === "approved"
                            ? "支給決定"
                            : state.status === "rejected"
                              ? "却下"
                              : `審査中：${STAGE_LABELS[state.currentStage]}`}
                    </Badge>
                </div>

                {isTerminal && (
                    <Banner
                        variant={
                            state.status === "approved" ? "success" : "destructive"
                        }
                        className="mb-4"
                        title={
                            state.status === "approved"
                                ? "この申請は支給決定済みです"
                                : "この申請は却下されました"
                        }
                    >
                        決定は署名・確定済みのため変更できません。修正は追記で行います。
                    </Banner>
                )}

                <div className="grid grid-cols-1 gap-6 lg:grid-cols-[minmax(0,1fr)_320px]">
                    {/* 左：審査本体 */}
                    <div className="flex flex-col gap-6">
                        <StageControls
                            app={app}
                            state={state}
                            advanceable={advanceable}
                            isTerminal={isTerminal}
                            onAdvance={advance}
                            sendBackTarget={sendBackTarget}
                            setSendBackTarget={setSendBackTarget}
                            sendBackReason={sendBackReason}
                            setSendBackReason={setSendBackReason}
                            onSendBack={sendBack}
                            rejectReason={rejectReason}
                            setRejectReason={setRejectReason}
                            onReject={reject}
                        />

                        {/* 段階別の作業領域 */}
                        {state.currentStage === "documents" && !isTerminal && (
                            <DocumentChecklist
                                app={app}
                                state={state}
                                onToggle={(id, checked) =>
                                    patchState({
                                        docChecks: {
                                            ...state.docChecks,
                                            [id]: checked,
                                        },
                                    })
                                }
                            />
                        )}

                        {state.currentStage === "eligibility" &&
                            !isTerminal && (
                                <EligibilityCard
                                    app={app}
                                    state={state}
                                    onConfirm={(v) =>
                                        patchState({ eligibilityConfirmed: v })
                                    }
                                />
                            )}

                        {state.currentStage === "household" && !isTerminal && (
                            <HouseholdSurvey
                                app={app}
                                state={state}
                                onDone={(v) =>
                                    patchState({ householdSurveyDone: v })
                                }
                            />
                        )}

                        {(state.currentStage === "decision" ||
                            state.completed.decision) && (
                            <DecisionCard
                                app={app}
                                state={state}
                                elig={elig}
                                amount={amount}
                                decision={decision}
                                onDecisionChange={onDecisionChange}
                                coSign={coSign}
                                onCoSign={(v) =>
                                    setCoSigns((prev) => ({
                                        ...prev,
                                        [selectedId]: v,
                                    }))
                                }
                                kind={decisionKind[selectedId] ?? "approve"}
                                setKind={(k) =>
                                    setDecisionKind((prev) => ({
                                        ...prev,
                                        [selectedId]: k,
                                    }))
                                }
                                reason={decisionReason[selectedId] ?? ""}
                                setReason={(r) =>
                                    setDecisionReason((prev) => ({
                                        ...prev,
                                        [selectedId]: r,
                                    }))
                                }
                            />
                        )}

                        {state.currentStage === "payment" &&
                            state.status === "approved" && (
                                <PaymentCard
                                    app={app}
                                    state={state}
                                    amount={amount}
                                    onComplete={completePayment}
                                />
                            )}
                    </div>

                    {/* 右：審査の流れ + 申請概要 */}
                    <aside className="flex flex-col gap-6">
                        <Card>
                            <CardHeader>
                                <CardTitle as="h3">審査の流れ</CardTitle>
                                <CardDescription>
                                    各段階の担当者・日時を記録します
                                </CardDescription>
                            </CardHeader>
                            <CardContent>
                                <ApprovalSteps steps={approvalSteps} />
                            </CardContent>
                        </Card>

                        <Card>
                            <CardHeader>
                                <CardTitle as="h3">申請概要</CardTitle>
                            </CardHeader>
                            <CardContent>
                                <MetadataList
                                    items={[
                                        {
                                            label: "給付種別",
                                            value: BENEFIT_LABELS[app.type],
                                        },
                                        {
                                            label: "申請日",
                                            value: fmtDate(app.appliedAt),
                                        },
                                        {
                                            label: "処理期限",
                                            value: (
                                                <SlaFlag dueAt={app.dueAt} />
                                            ),
                                        },
                                        {
                                            label: "世帯人数",
                                            value: `${app.householdSize}人`,
                                        },
                                        {
                                            label: "連絡先",
                                            value: app.contact,
                                        },
                                        {
                                            label: "住所",
                                            value: app.address,
                                        },
                                    ]}
                                />
                            </CardContent>
                        </Card>
                    </aside>
                </div>
            </section>
        </main>
    );
}

// ---------------------------------------------------------------------------
// 段階の進行コントロール（次へ進める / 差戻し / 却下）
// ---------------------------------------------------------------------------
function StageControls({
    app,
    state,
    advanceable,
    isTerminal,
    onAdvance,
    sendBackTarget,
    setSendBackTarget,
    sendBackReason,
    setSendBackReason,
    onSendBack,
    rejectReason,
    setRejectReason,
    onReject,
}: {
    app: Application;
    state: ScreeningState;
    advanceable: boolean;
    isTerminal: boolean;
    onAdvance: () => void;
    sendBackTarget: StageId | "";
    setSendBackTarget: (s: StageId | "") => void;
    sendBackReason: string;
    setSendBackReason: (s: string) => void;
    onSendBack: () => void;
    rejectReason: string;
    setRejectReason: (s: string) => void;
    onReject: () => void;
}) {
    const stage = state.currentStage;
    const next = nextStage(stage);
    const priors = priorStages(stage);
    const decisionStage = stage === "decision";
    const paymentStage = stage === "payment";

    return (
        <Card>
            <CardHeader>
                <CardTitle as="h3" className="flex items-center gap-2">
                    現在の段階：{STAGE_LABELS[stage]}
                </CardTitle>
                <CardDescription>
                    要件：{STAGE_REQUIREMENT[stage]}
                </CardDescription>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
                {!advanceable && !isTerminal && !decisionStage && !paymentStage && (
                    <Alert variant="warning">
                        <AlertTitle>次へ進めません</AlertTitle>
                        <AlertDescription>
                            この段階の要件が満たされていないため「次へ進める」は無効です。
                        </AlertDescription>
                    </Alert>
                )}

                {decisionStage && !isTerminal && (
                    <Alert variant="info">
                        <AlertTitle>決定段階</AlertTitle>
                        <AlertDescription>
                            下の「決定」で承認/却下を署名・確定すると、次段階（支給）へ進みます。
                        </AlertDescription>
                    </Alert>
                )}

                <div className="flex flex-wrap gap-2">
                    {/* 次へ進める */}
                    {!isTerminal && !decisionStage && !paymentStage && (
                        <Button
                            variant="default"
                            onClick={onAdvance}
                            disabled={!advanceable || !next}
                        >
                            <IconArrowRight className="h-4 w-4" aria-hidden />
                            次へ進める
                            {next ? `（${STAGE_LABELS[next]}）` : ""}
                        </Button>
                    )}

                    {/* 差戻し */}
                    {!isTerminal && priors.length > 0 && (
                        <AlertDialog>
                            <AlertDialogTrigger asChild>
                                <Button variant="outline">
                                    <IconArrowBackUp
                                        className="h-4 w-4"
                                        aria-hidden
                                    />
                                    差戻し
                                </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                                <AlertDialogHeader>
                                    <AlertDialogTitle>
                                        前の段階に差戻し
                                    </AlertDialogTitle>
                                    <AlertDialogDescription>
                                        戻す段階と理由を記録します。戻し先以降の確認は取り消されます。
                                    </AlertDialogDescription>
                                </AlertDialogHeader>
                                <div className="flex flex-col gap-3 py-2">
                                    <Select
                                        label="戻し先の段階"
                                        value={sendBackTarget}
                                        onChange={(e) =>
                                            setSendBackTarget(
                                                e.target.value as StageId | "",
                                            )
                                        }
                                    >
                                        <option value="">選択してください</option>
                                        {priors.map((s) => (
                                            <option key={s} value={s}>
                                                {STAGE_LABELS[s]}
                                            </option>
                                        ))}
                                    </Select>
                                    <Textarea
                                        label="差戻し理由（必須）"
                                        rows={3}
                                        value={sendBackReason}
                                        onChange={(e) =>
                                            setSendBackReason(e.target.value)
                                        }
                                        placeholder="例：収入証明の添付が不足しているため。"
                                    />
                                </div>
                                <AlertDialogFooter>
                                    <AlertDialogCancel
                                        onClick={() => {
                                            setSendBackTarget("");
                                            setSendBackReason("");
                                        }}
                                    >
                                        キャンセル
                                    </AlertDialogCancel>
                                    <AlertDialogAction
                                        onClick={onSendBack}
                                        disabled={
                                            !sendBackTarget ||
                                            !sendBackReason.trim()
                                        }
                                    >
                                        差戻す
                                    </AlertDialogAction>
                                </AlertDialogFooter>
                            </AlertDialogContent>
                        </AlertDialog>
                    )}

                    {/* 却下 */}
                    {!isTerminal && !paymentStage && (
                        <AlertDialog>
                            <AlertDialogTrigger asChild>
                                <Button variant="destructive">
                                    <IconBan className="h-4 w-4" aria-hidden />
                                    却下
                                </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                                <AlertDialogHeader>
                                    <AlertDialogTitle>
                                        申請を却下
                                    </AlertDialogTitle>
                                    <AlertDialogDescription>
                                        却下理由は申請者に通知され、記録に残ります。この操作は審査を終了します。
                                    </AlertDialogDescription>
                                </AlertDialogHeader>
                                <div className="py-2">
                                    <Textarea
                                        label="却下理由（必須）"
                                        rows={3}
                                        value={rejectReason}
                                        onChange={(e) =>
                                            setRejectReason(e.target.value)
                                        }
                                        placeholder="例：世帯収入が基準額を超過しているため。"
                                    />
                                </div>
                                <AlertDialogFooter>
                                    <AlertDialogCancel
                                        onClick={() => setRejectReason("")}
                                    >
                                        キャンセル
                                    </AlertDialogCancel>
                                    <AlertDialogAction
                                        onClick={onReject}
                                        disabled={!rejectReason.trim()}
                                    >
                                        却下する
                                    </AlertDialogAction>
                                </AlertDialogFooter>
                            </AlertDialogContent>
                        </AlertDialog>
                    )}
                </div>
            </CardContent>
        </Card>
    );
}

