// ----- 資格判定 (eligibility: income vs threshold, household, assets) -------
// 月収の基準額。世帯人数で逓増（簡易モデル）。
export function incomeThreshold(householdSize: number): number {
    const base = 138000; // 1人世帯
    const perExtra = 45000; // 2人目以降の加算
    return base + Math.max(0, householdSize - 1) * perExtra;
}

// 資産（預貯金）の基準額
export const ASSET_THRESHOLD = 1000000;

// ----- 支給額計算 (benefit amount) -----------------------------------------
export function computeBenefitAmount(
    type: BenefitType,
    householdSize: number,
    monthlyIncome: number,
): number {
    const threshold = incomeThreshold(householdSize);
    if (type === "childRearing") {
        // 一時金：児童相当（世帯人数−1 を子と仮定、上限3）
        const children = Math.min(Math.max(householdSize - 1, 0), 3);
        return 50000 * Math.max(children, 1);
    }
    if (type === "housing") {
        // 住居確保：上限53,700円（単身）+ 世帯加算
        const cap = 53700 + Math.max(0, householdSize - 1) * 10000;
        return cap;
    }
    // 生活支援：基準額と収入の差額（不足分）を補填、最低10,000円
    const shortfall = threshold - monthlyIncome;
    return Math.max(10000, Math.min(shortfall, threshold));
}

