// ----------------------------------------------------------------------------
// 審査ワークフローの実行時状態（ハンドロール状態機械）
// ----------------------------------------------------------------------------
export interface ScreeningState {
    appId: string;
    /** 現在の段階 */
    currentStage: StageId;
    /** 段階ごとの完了記録（actor/at/note） */
    completed: Partial<Record<StageId, StageRecord>>;
    status: ScreeningStatus;
    /** 必要書類のチェック状態 */
    docChecks: Record<string, boolean>;
    /** 資格判定の人手確認（基準超過でも特例承認を可とするか等の確定フラグ） */
    eligibilityConfirmed: boolean;
    /** 世帯・収入調査の完了フラグ */
    householdSurveyDone: boolean;
}

export function initialScreeningState(app: Application): ScreeningState {
    const docs = REQUIRED_DOCS[app.type];
    return {
        appId: app.id,
        currentStage: "intake",
        completed: {},
        status: "inReview",
        docChecks: Object.fromEntries(docs.map((d) => [d.id, false])),
        eligibilityConfirmed: false,
        householdSurveyDone: false,
    };
}

export interface EligibilityResult {
    threshold: number;
    incomeOver: boolean;
    assetsOver: boolean;
    /** 総合判定：基準内なら true */
    eligible: boolean;
}

export function evaluateEligibility(
    app: Application,
    state: ScreeningState,
): EligibilityResult {
    const threshold = incomeThreshold(app.householdSize);
    const incomeOver = app.monthlyIncome > threshold;
    const assetsOver = app.assets > ASSET_THRESHOLD;
    return {
        threshold,
        incomeOver,
        assetsOver,
        eligible: !incomeOver && !assetsOver,
    };
}

/** その段階の要件が満たされているか（次へ進めるゲート） */
export function canAdvance(app: Application, state: ScreeningState): boolean {
    if (state.status !== "inReview") return false;
    switch (state.currentStage) {
        case "intake":
            return true;
        case "documents": {
            const docs = REQUIRED_DOCS[app.type];
            return docs
                .filter((d) => !d.optional)
                .every((d) => state.docChecks[d.id]);
        }
        case "eligibility":
            return state.eligibilityConfirmed;
        case "household":
            return state.householdSurveyDone;
        case "decision":
            // 決定段階は SignedRecord の署名で進む（ボタンでは進めない）
            return false;
        case "payment":
            return false;
        default:
            return false;
    }
}

export function nextStage(stage: StageId): StageId | null {
    const i = STAGE_ORDER.indexOf(stage);
    return i >= 0 && i < STAGE_ORDER.length - 1 ? STAGE_ORDER[i + 1] : null;
}

/** 現在より前の段階だけが差戻し対象 */
export function priorStages(stage: StageId): StageId[] {
    const i = STAGE_ORDER.indexOf(stage);
    return STAGE_ORDER.slice(0, Math.max(i, 0));
}

export function stageStateFor(
    stage: StageId,
    state: ScreeningState,
): "pending" | "current" | "approved" | "rejected" | "skipped" {
    if (state.status === "rejected" && stage === state.currentStage) {
        return "rejected";
    }
    if (state.completed[stage]) return "approved";
    if (stage === state.currentStage && state.status === "inReview") {
        return "current";
    }
    return "pending";
}
